import AsyncStorage from '@react-native-async-storage/async-storage';
import { Platform } from 'react-native';

const DEBUG_MODE = __DEV__ || process.env.NODE_ENV === 'development';

class DebugLogger {
  constructor() {
    this.networkRequests = [];
    this.asyncStorageOperations = [];
    this.userActions = [];
    this.stateChanges = [];
    this.authTokens = [];
    this.userData = [];
    this.apiResponses = [];
    this.startTime = Date.now();
  }

  logNetworkRequest(request) {
    if (!DEBUG_MODE) return;
    
    const logEntry = {
      type: 'network_request',
      timestamp: Date.now(),
      duration: Date.now() - this.startTime,
      method: request.method,
      url: request.url,
      headers: request.headers,
      body: request.body,
      id: this.generateId()
    };

    this.networkRequests.push(logEntry);
    console.log('Network Request:', logEntry);
  }

  logNetworkResponse(response) {
    if (!DEBUG_MODE) return;
    
    const logEntry = {
      type: 'network_response',
      timestamp: Date.now(),
      duration: Date.now() - this.startTime,
      url: response.url,
      status: response.status,
      statusText: response.statusText,
      headers: response.headers,
      responseSize: response.headers.get('content-length'),
      id: this.generateId()
    };

    this.apiResponses.push(logEntry);
    console.debug('Network Response:', logEntry);
  }

  logAsyncStorageOperation(operation, key, value) {
    if (!DEBUG_MODE) return;
    
    const logEntry = {
      type: 'async_storage',
      timestamp: Date.now(),
      duration: Date.now() - this.startTime,
      operation,
      key,
      value: this.sanitizeValue(value),
      id: this.generateId()
    };

    this.asyncStorageOperations.push(logEntry);
    console.log('AsyncStorage Operation:', logEntry);
  }

  logUserAction(action, data) {
    if (!DEBUG_MODE) return;
    
    const logEntry = {
      type: 'user_action',
      timestamp: Date.now(),
      duration: Date.now() - this.startTime,
      action,
      data: this.sanitizeData(data),
      id: this.generateId()
    };

    this.userActions.push(logEntry);
    console.log('User Action:', logEntry);
  }

  logStateChange(prevState, nextState, action) {
    if (!DEBUG_MODE) return;
    
    const logEntry = {
      type: 'state_change',
      timestamp: Date.now(),
      duration: Date.now() - this.startTime,
      action,
      prevState: this.sanitizeData(prevState),
      nextState: this.sanitizeData(nextState),
      id: this.generateId()
    };

    this.stateChanges.push(logEntry);
    console.debug('State Change:', logEntry);
  }

  logAuthToken(token) {
    if (!DEBUG_MODE) return;
    
    const logEntry = {
      type: 'auth_token',
      timestamp: Date.now(),
      duration: Date.now() - this.startTime,
      token: this.maskToken(token),
      id: this.generateId()
    };

    this.authTokens.push(logEntry);
    console.debug('Auth Token:', logEntry);
  }

  logUserData(userData) {
    if (!DEBUG_MODE) return;
    
    const logEntry = {
      type: 'user_data',
      timestamp: Date.now(),
      duration: Date.now() - this.startTime,
      data: this.sanitizeUserData(userData),
      id: this.generateId()
    };

    this.userData.push(logEntry);
    console.debug('User Data:', logEntry);
  }

  sanitizeValue(value) {
    if (value === null || value === undefined) return value;
    if (typeof value === 'string') {
      return value.length > 1000 ? `${value.substring(0, 1000)}...` : value;
    }
    if (typeof value === 'object') {
      return JSON.stringify(value, (key, val) => {
        if (key === 'password' || key === 'token' || key === 'secret') return '[REDACTED]';
        return val;
      });
    }
    return value;
  }

  sanitizeData(data) {
    if (!data) return data;
    return this.sanitizeValue(data);
  }

  sanitizeUserData(userData) {
    if (!userData) return userData;
    return this.sanitizeValue(userData);
  }

  maskToken(token) {
    if (!token || typeof token !== 'string') return token;
    if (token.length < 8) return token;
    return token.substring(0, 4) + '***' + token.substring(token.length - 4);
  }

  generateId() {
    return Math.random().toString(36).substr(2, 9);
  }

  getLogs() {
    return {
      networkRequests: this.networkRequests,
      asyncStorageOperations: this.asyncStorageOperations,
      userActions: this.userActions,
      stateChanges: this.stateChanges,
      authTokens: this.authTokens,
      userData: this.userData,
      apiResponses: this.apiResponses,
      timestamp: Date.now()
    };
  }

  clearLogs() {
    this.networkRequests = [];
    this.asyncStorageOperations = [];
    this.userActions = [];
    this.stateChanges = [];
    this.authTokens = [];
    this.userData = [];
    this.apiResponses = [];
  }

  exportLogs() {
    if (!DEBUG_MODE) return;
    
    const logs = this.getLogs();
    console.log('Debug Logs Export:', logs);
    
    // In production, this would be sent to your backend
    // For example: sendToBackend(logs);
    
    return logs;
  }

  // Enhanced logging methods for specific scenarios
  logError(error, context = '') {
    if (!DEBUG_MODE) return;
    
    console.error('Error Context:', {
      timestamp: Date.now(),
      context,
      error: error.message,
      stack: error.stack,
      id: this.generateId()
    });
  }

  logWarning(warning, context = '') {
    if (!DEBUG_MODE) return;
    
    console.warn('Warning Context:', {
      timestamp: Date.now(),
      context,
      warning,
      id: this.generateId()
    });
  }
}

